import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"🚀 Not Boring — 2026-05-28","description":"","frontmatter":{},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-28-not-boring.md","filePath":"research/ai-news/2026-05/2026-05-28-not-boring.md","lastUpdated":1779935873000}'),n={name:"research/ai-news/2026-05/2026-05-28-not-boring.md"};function s(i,e,l,h,c,p){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="🚀-not-boring-—-2026-05-28" tabindex="-1">🚀 Not Boring — 2026-05-28 <a class="header-anchor" href="#🚀-not-boring-—-2026-05-28" aria-label="Permalink to &quot;🚀 Not Boring — 2026-05-28&quot;">​</a></h1><blockquote><p>Packy McCormick 的科技商業策略深度文；以敘事帶動的長篇市場分析 來源：<a href="https://www.notboring.co/feed" target="_blank" rel="noreferrer">Not Boring</a></p></blockquote><hr><h2 id="thank-god-for-data-centers" tabindex="-1"><a href="https://www.notboring.co/p/thank-god-for-data-centers" target="_blank" rel="noreferrer">Thank God For Data Centers</a> <a class="header-anchor" href="#thank-god-for-data-centers" aria-label="Permalink to &quot;[Thank God For Data Centers](https://www.notboring.co/p/thank-god-for-data-centers)&quot;">​</a></h2><p><em>🚀 Not Boring | 2026-05-27</em></p><p>_Welcome to the<strong>2,232 newly Not Boring people</strong> who have joined us since our <a href="https://www.notboring.co/p/riding-the-leopard" target="_blank" rel="noreferrer">last essay</a>! Join<strong>267,788</strong> smart, curious folks by subscribing here: _</p><p><a href="https://www.notboring.co/subscribe" target="_blank" rel="noreferrer">Subscribe now</a></p><hr><p>Hi friends 👋,</p><p>Happy Wednesday!</p><p>A couple weeks ago, I asked if you wanted me to start sharing more off-the-cuff notes with not boring world subscribers, and the response was great, so we&#39;re back. It&#39;s a Wednesday afternoon, not my normal send time, but these are meant to be less formal and more, &quot;I noticed something interesting, here are my quick thoughts.&quot; This one happens to be a little longer than it is quick, but it&#39;s one I wanted to get out for two reasons:</p><ol><li><p>People hate AI Data Centers, and I think they&#39;re wrong, even if they don&#39;t like AI.</p></li><li><p>Because I keep hearing, reading, and seeing that AI Data Centers are funding new technologies before they&#39;ve come down the learning curve, which might be a providentially big boon to Reindustrialization and all of the hard, physical things we want to see in the world.</p></li></ol><p>It&#39;s pretty beautiful that gaming chips that evolved from Apollo-funded integrated circuits are creating a product with so much demand that their houses can pay for all sorts of novel technologies, like the Apollo Program did.</p><p>Let&#39;s get to it.</p><hr><h3 id="today-s-not-boring-is-brought-to-you-by-deel" tabindex="-1"><strong>Today &#39;s Not Boring is brought to you by… <a href="https://www.deel.com/resources/a-guide-to-eor-for-startups/?utm_medium=sponsored-newsletter&amp;utm_source=notboring&amp;utm_campaign=ww_engage_download_notboring_sponnewsletter_smb-eorforstartups-apr26_eor_smb&amp;utm_content=engage_eor_sponnewsletter_eorforstartups-sponnews180-smb_en" target="_blank" rel="noreferrer">Deel</a></strong> <a class="header-anchor" href="#today-s-not-boring-is-brought-to-you-by-deel" aria-label="Permalink to &quot;**Today &#39;s Not Boring is brought to you by… [Deel](https://www.deel.com/resources/a-guide-to-eor-for-startups/?utm_medium=sponsored-newsletter&amp;utm_source=notboring&amp;utm_campaign=ww_engage_download_notboring_sponnewsletter_smb-eorforstartups-apr26_eor_smb&amp;utm_content=engage_eor_sponnewsletter_eorforstartups-sponnews180-smb_en)**&quot;">​</a></h3><p><em><strong>Hiring globally doesn &#39;t have to be complicated</strong></em></p><p><a href="https://www.deel.com/resources/a-guide-to-eor-for-startups/?utm_medium=sponsored-newsletter&amp;utm_source=notboring&amp;utm_campaign=ww_engage_download_notboring_sponnewsletter_smb-eorforstartups-apr26_eor_smb&amp;utm_content=engage_eor_sponnewsletter_eorforstartups-sponnews180-smb_en" target="_blank" rel="noreferrer"></a></p><p><em>Hiring globally can unlock growth, but local laws, payroll, and compliance often slow startups down.</em></p><p><em><a href="https://www.deel.com/resources/a-guide-to-eor-for-startups/?utm_medium=sponsored-newsletter&amp;utm_source=notboring&amp;utm_campaign=ww_engage_download_notboring_sponnewsletter_smb-eorforstartups-apr26_eor_smb&amp;utm_content=engage_eor_sponnewsletter_eorforstartups-sponnews180-smb_en" target="_blank" rel="noreferrer">Deel&#39;s</a> free guide breaks down what an Employer of Record (EOR) is, how startups use EORs to hire internationally without opening entities, and when it makes sense to use one so you can scale with confidence.</em></p><p><a href="https://www.deel.com/resources/a-guide-to-eor-for-startups/?utm_medium=sponsored-newsletter&amp;utm_source=notboring&amp;utm_campaign=ww_engage_download_notboring_sponnewsletter_smb-eorforstartups-apr26_eor_smb&amp;utm_content=engage_eor_sponnewsletter_eorforstartups-sponnews180-smb_en" target="_blank" rel="noreferrer">Download Now</a></p><hr><h1 id="thank-god-for-data-centers-1" tabindex="-1">Thank God for Data Centers <a class="header-anchor" href="#thank-god-for-data-centers-1" aria-label="Permalink to &quot;Thank God for Data Centers&quot;">​</a></h1><p><a href="https://substackcdn.com/image/fetch/$s_!zhh6!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fa23d4a7f-dcb2-4b76-b601-6b43607a98be_1200x603.png" target="_blank" rel="noreferrer"></a></p><p>There exists a vast pool of technologies that are potentially superior to those we employ today, but which require scale and learning curves to reach their potential.</p><p>Advanced nuclear reactors are one such technology - they are more expensive than alternatives today, but manufactured at scale, and benefiting from the learning curves required to get there, may become cheaper than other generation technologies. The cost physics are on their side, and nuclear is reliable, safe, firm, and clean.</p><p>The challenge with these technologies, in normal times, is that there is little economic incentive for the buyers who would enable the scale to stick their necks out. Natural gas is cheap and abundant, and it&#39;s not <em>that</em> bad for the environment, compared to coal and oil at least, and the environment is someone else&#39;s problem, anyway. And so, in normal times, we remain stuck in local maxima without the demand to push towards global ones.</p><p>Historically, these stalemates have cracked in a couple of main ways: <strong>Alpha Products</strong> and extraeconomic <strong>Buyers of Capabilities</strong>. These are essentially the same mechanism at different scales and with different motivations.</p><p>In _<a href="https://www.notboring.co/p/the-electric-slide" target="_blank" rel="noreferrer">The Electric Slide</a>, _we discussed the role that <strong>Alpha Products</strong> played in providing the initial demand that eventually brought each layer of the Electric Stack down their respective cost-performance curves. For lithium-ion batteries, the alpha product was the Sony Handycam. For neodymium magnets and motors, it was the 3.5&quot; hard‑disk drive. For power electronics (IGBTs / inverters), it was the variable‑frequency drive (VFD) for industrial motors. For microcontrollers (MCUs), it was the calculator. Etc.</p><p>For each of these, the new technology was advantageous enough in a specific way to the end product that it was worth paying higher costs or sacrificing on other capabilities to capture those benefits.</p><p>Alpha Products, however, typically support components that are not multi-hundred million or multi-billion dollar projects in their own right.</p><p>The role of the extraeconomic <strong>Buyer of Capabilities</strong> in the development of new technologies is even better-understood. This is the DoD or NASA, mainly, buying technologies to confer a specific advantage, almost irrespective of their cost. This category of customer cares less about price than about capability.</p><p>Theirs is an important role because it gives new technologies the opportunity to get to scale, come down the learning curve, and ultimately compete in the much larger commercial market.</p><p>For a while now, but particularly over the past couple of weeks, I&#39;ve heard some version of the same story over and over again:</p><p><strong>&quot; We are still going after our long-term mission, but to fund it, we&#39;re planning to sell to data centers.&quot;</strong></p><p>Today, <strong>Data Centers are increasingly serving as Buyers of Capabilities, acting as something between a government and a commercial buyer</strong>. The Data Center is the meta-Alpha Product. If you can sell them something they need, fast, they have an almost bottomless bid.</p><p>This is true for obvious things like GPUs, inference chips, and DRAM, but it&#39;s also true for companies that you wouldn&#39;t typically associate with AI data centers, like supersonic turbines, enhanced geothermal, modular construction, high-voltage direct current grids, solid-state transformers, silicon photonics, optical fiber, lasers, batteries, and nuclear.</p><p>Many of these technologies have the <em>potential</em> to be better and cheaper than the incumbent technologies they aim to replace, but they have been too expensive and unproven to compete. With backlogs in all of the traditional inputs to Data Centers, however, developers are willing to pay up for new technologies that can deliver fast, which gives them the opportunity to scale up and cost down.</p><p>For these technologies, Data Centers act as a third type of Buyer of Capabilities, a commercial analog operating on DoD-style procurement logic but commercial timescales.</p><p>Given the size of the budgets, the relative smallness of any one input&#39;s cost relative to the overall project cost and revenue opportunity, and the speed with which Data Centers are making decisions and putting down deposits, <strong>Data Centers may meaningfully increase the odds of success of hard tech companies and<a href="https://www.notboring.co/p/vertical-integrators" target="_blank" rel="noreferrer">Vertical Integrators</a> more than the market realizes.</strong></p><p>Far from being the villains they are painted as (often using <a href="https://x.com/kevinolearytv/status/2059036986623819815?s=20" target="_blank" rel="noreferrer">misinformation</a> and largely due to their association with <a href="https://www.pewresearch.org/short-reads/2026/03/12/key-findings-about-how-americans-view-artificial-intelligence/" target="_blank" rel="noreferrer">deeply unpopular AI</a>), Data Centers may be the greatest accelerant of American Reindustrialization and a built-world future that benefits all people that we&#39;ve ever seen.</p><p>They offer dilution-free capital (real revenue on a negative working capital cycle) to fund the big vision, and more importantly, the opportunity to get to scale and down the learning curve years earlier than would otherwise have been possible. This both accelerates timelines of things that might have worked, but more slowly, and makes companies that might otherwise have died in the Valley of Death viable.</p><p>Whatever your feelings are on AI, the furor towards Data Centers is misplaced. Hell, whether or not you think we&#39;re in an AI Bubble barely matters here. In five years, this could all fall apart, and the world will be much better off. Data Centers are funding the future where no one else will.</p><p>This isn&#39;t the first time that people have gotten mad that something that seems frivolous is sucking up so many resources. The immediate stuff - like how much money is being spent or power is being consumed - is an easy target, while the long-term benefits are hard to see.</p><h3 id="we-choose-to-go-to-the-moon-not-because-it-is-popular" tabindex="-1"><strong>We Choose to Go to the Moon Not Because it is Popular</strong> <a class="header-anchor" href="#we-choose-to-go-to-the-moon-not-because-it-is-popular" aria-label="Permalink to &quot;**We Choose to Go to the Moon Not Because it is Popular**&quot;">​</a></h3><p>With the benefit of hindsight and distance, the Apollo mission has become one of America&#39;s proudest accomplishments. At the time, though, not everyone loved JFK taking us to the Moon. There were too many problems on Earth to be solved to waste all that time, money, and smarts on a lunar boondoggle.</p><p>In May 1961, <a href="https://ropercenter.cornell.edu/sites/default/files/2018-07/55088.pdf" target="_blank" rel="noreferrer">Gallup asked Americans</a>, &quot;It has been estimated that it would cost the United States 40 billion dollars-or an average of about $225 per person-to send a man to the moon. Would you like to see this amount spent for this purpose, or not?&quot; 58% of respondents said that they would not, another 9% had no opinion, and only 33% supported the mission.</p><p>President John F. Kennedy gave his canonical &quot;We choose to go to the Moon&quot; speech not because it was popular, but because it was unpopular and he needed to rally support.</p><p>It didn&#39;t work that well. In a 1964 Gallup poll that asked &quot;Do you think the United States should go all out to beat the Russians in a manned-flight to the moon-or don&#39;t you think this is too important?&quot;, 66% of respondents said that they did not think it was too important, and another 8% said &quot;Don&#39;t know,&quot; which amounts to the same thing. In the <a href="https://launiusr.wordpress.com/2010/08/16/exploding-the-myth-of-popular-support-for-project-apollo/" target="_blank" rel="noreferrer">summer of 1965</a>, &quot;one-third of the nation favored cutting the space budget, while only 16% wanted to increase it.&quot;</p><p>Even a decade after NASA pulled off the near-impossible, in 1979, only 41% of Americans told an <a href="https://news.gallup.com/poll/3712/landing-man-moon-publics-view.aspx" target="_blank" rel="noreferrer">NBC/AP poll</a> that the benefits of the space program outweighed the costs. By 1995, that had risen to 47%, by 1999 it hit 55%, and by the 50th anniversary of the Moon Landing, in 2019, support had reached 64%.</p><p><a href="https://substackcdn.com/image/fetch/$s_!jp-C!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F278eb235-bae2-445c-bd1b-50e94342f60b_728x417.png" target="_blank" rel="noreferrer"></a></p><p>One explanation is that, not having to pay the costs ourselves but getting to bask in the memory of victory, today&#39;s Americans can of course look back and say it was worth it.</p><p>Another, though, is that over time, the real benefits, not at all obvious at the time, have become more clear.</p><p>Apollo&#39;s critics were ultimately proven wrong, both because beating the Soviets to the Moon was awesome…</p><p><a href="https://substackcdn.com/image/fetch/$s_!YD30!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F32bebc4d-abd0-46d7-8839-195fe83f509a_908x721.png" target="_blank" rel="noreferrer"></a></p><p>… and more directly because the absurdity of the task&#39;s ambition coupled with the bottomlessness of its budget that they complained about were exactly the conditions needed to create terrestrially-useful innovations that would otherwise have taken much longer, or never been invented at all.</p><p>While the role that the Apollo Program played in <em>inventing</em> new technologies is probably overblown, it accelerated, scaled, and de-risked a lot of things that otherwise may not have gotten to sufficient scale or cost to impact our lives. Some of the technologies and products for which they served this role include:</p><ul><li><p>Fireproof fabrics and flame-retardant materials (developed after the Apollo 1 fire), which made their way into firefighter suits and racing gear</p></li><li><p>Improved freeze-drying processes for food preservation</p></li><li><p>Mylar-based reflective insulation, which became the emergency space blanket</p></li><li><p>Advances in composite materials and ablative coatings</p></li><li><p>CAT and MRI imaging benefited from digital image processing techniques developed to enhance lunar photographs at JPL</p></li><li><p>Implantable cardiac pacemakers improved from bidirectional telemetry developed for astronaut biosensors</p></li><li><p>Cool suits (liquid-cooled garments) used for MS patients, burn victims, and racing drivers came directly from the spacesuit undergarment</p></li><li><p>Kidney dialysis machines used a chemical process developed to remove toxins from astronauts&#39; water</p></li><li><p>Black &amp; Decker developed the technology to make cordless power tools for collecting lunar samples</p></li><li><p>NASA developed Memory foam (Temper Foam) for crash protection in seats</p></li><li><p>Water filtration using silver ions, based on the system that purified the Apollo crew&#39;s water</p></li><li><p>Scratch-resistant lens coatings, derived from coatings developed for astronaut visors</p></li><li><p>Improved smoke detectors (the modern ionization-type was refined for Skylab, which leveraged Apollo hardware)</p></li></ul><p>Even cleanroom protocols for handling lunar samples spread into pharmaceuticals and, relevant to today&#39;s discussion, semiconductor manufacturing.</p><p>That&#39;s just one program, albeit a very large one. If you zoom out to include the technologies that received early support from the DoD, the list includes pretty much everything that defines modern life.</p><p>The internet and TCP/IP directly, and Ethernet indirectly. Satellite communications, GPS, the inertial navigation systems that run in our phones and cars, and radio navigation. The mouse, windowing interfaces, and hypertext; the work that Doug Engelbart showed off in his &quot;<a href="https://en.wikipedia.org/wiki/The_Mother_of_All_Demos" target="_blank" rel="noreferrer">Mother of All Demos</a>&quot; was ARPA-funded. Public-key cryptography was invented for UK SigInt, Grace Hopper developed COBOL on the Navy&#39;s dime, and DARPA funded the first AI labs at MIT, Stanford, CMU, and Stanford Research Institute for decades. The chips AI runs on, GPUs, and the CUDA software behind them, owe something to DARPA-funded parallel computing research. Siri&#39;s lineage, for better or worse, through DARPA&#39;s CALO speech recognition program at SRI. There are the more obviously military products, like the jet engine and the planes jet engines power, stealth coatings, night vision, radar and synthetic aperture radar, Lidar, ultrasound, drones, and infrared and thermal imaging. There are materials, like composites, including carbon fiber, titanium alloys, and advanced ceramics, all of which scaled through defense procurement. LEDs were funded through early signaling work, and digital photography found a buyer in early spy planes. In medicine, we have the DoD to thank for EpiPens, tourniquets, hemostatic agents like QuikClot, prosthetics, blood banking, and plasma storage. Penicillin was first mass-produced in a wartime crash program. And energy? Civilian nuclear power descended directly from Admiral Rickover&#39;s Naval reactor program, lithium-ion battery research had defense funding, and solar photovoltaic cells were pulled forward by satellites&#39; unique power needs.</p><p>Military procurement is the closest thing that the United States has to a national industrial policy, and its worked. The military has funded the development of practically every general purpose technology of the past century, before the commercial market took those de-risked, cost-downed technologies and figured out how to bring them to the masses.</p><p>Of all of these, the cleanest case study and the one that maps most directly onto what&#39;s happening in 2026, is the integrated circuit.</p><h4 id="minuteman-apollo-and-moore-s-law" tabindex="-1"><em><strong>Minuteman, Apollo, and Moore &#39;s Law</strong></em> <a class="header-anchor" href="#minuteman-apollo-and-moore-s-law" aria-label="Permalink to &quot;_**Minuteman, Apollo, and Moore &#39;s Law**_&quot;">​</a></h4><p>Fairchild Semiconductor was founded in 1957 as a transistor company, and its first big customer was the military.</p><p>Specifically, facing a threat from larger Soviet boosters that could launch intercontinental ballistic missiles (ICBMs) that could fit vacuum tubes, the US military, with its smaller boosters, had to invest in miniaturization, which meant transistors. Between 1958 and 1960, Fairchild&#39;s revenue grew from $500k to $21 million, largely on the back of the Minuteman I program, for which it produced custom designs. Challenge was, as the number of transistors grew, the electronics industry ran into the &quot;tyranny of numbers&quot;: now that they could, engineers wanted to design circuits with thousands of components, all of which had to be wired together by hand.</p><p>So in Dallas, Texas Instruments&#39; Jack Kilby came up with his &quot;monolithic idea.&quot; &quot;He realized that,&quot; Carl Leonard <a href="https://nowweknowem.wordpress.com/2013/09/12/jack-kilby-developed-the-first-integrated-circuit-and-demonstrated-its-success-to-his-employer-texas-instruments-today-in-1958-leading-to-his-noble-prize-in-physics-now-we-know-em/" target="_blank" rel="noreferrer">writes</a>, &quot;instead of connecting separate components, an entire electronic assembly could be made as one unit from one semiconducting material by overlaying it with various impurities to replicate individual electronic components, such as resistors, capacitors, and transistors.&quot; He had invented the integrated circuit (IC).</p><p>Three months later, in Mountain View, Fairchild co-founder Bob Noyce arrived at a similar idea from a different angle. Starting from the planar process, invented by Jean Hoerni in early 1959, Noyce realized that you could build transistors flat on a silicon wafer, with all the connections on the top surface, protected by a layer of silicon oxide. He wrote in his <a href="https://www.technologyreview.com/2005/10/01/39552/the-integrator/" target="_blank" rel="noreferrer">notebook</a>, &quot;In many applications now it would be desirable to make multiple devices on a single piece of silicon in order to be able to make interconnections between devices as part of the manufacturing process, and thus reduce size, weight, etc., as well as cost per active element,&quot; and filed a patent that year.</p><p>While there are differences between the ICs they developed (Kilby&#39;s used Geranium and Noyce&#39;s silicon, for example), the two are credited as the co-inventor of the IC. What matters for our story is 1) the IC may not have been developed without demand from the Air Force, Army, and Navy, which were each spending real money on parallel attempts to solve it, and 2) Fairchild was now in the IC business.</p><p>In 1961, after starting at $1,000 per chip on tiny pilot runs the year before, Fairchild brought the integrated circuit to market at $120 per chip. The challenge was, no one really needed an integrated circuit, not enough to pay that price. Any electronics firm could wire together discrete transistors to do the same thing for a fraction of the price. As <a href="https://www.britannica.com/money/Fairchild-Semiconductor" target="_blank" rel="noreferrer">Britannica</a> puts it, &quot;a buyer had to have a serious space constraint to justify purchasing ICs.&quot; Fortunately for Fairchild, NASA had a serious space constraint.</p><p>In early 1962, MIT&#39;s Instrumentation Lab, which was responsible for the Apollo Guidance Computer (AGC), placed a test order for 100 ICs at $43.50 per unit. Meanwhile, getting ahead of volume and hoping to use scale to rev aerospace demand, Noyce cut the price of the IC from $120 to $15, an 87.5% drop, while still charging NASA and MIT premium prices to fund scale. &quot;Noyce slashed prices, too, gambling that this would drastically expand the civilian market for chips, Chris Miller wrote in <em><a href="https://www.amazon.com/Chip-War-Worlds-Critical-Technology/dp/1982172002" target="_blank" rel="noreferrer">Chip War</a></em>. &quot;In the mid-1960s, Fairchild chips that previously sold for $20 were cut to $2. At times Fairchild even sold products below manufacturing cost, hoping to convince more customers to try them.&quot;</p><p>Meanwhile, the government funded the gap. That November, MIT decided to go with Fairchild&#39;s IC, or more specifically, its Micrologic computer made up of ICs. By 1963, MIT was consuming 60% of US IC production for the AGC; other military and aerospace buyers made up the rest. In a <a href="https://spectrum.ieee.org/how-much-did-early-transistors-cost" target="_blank" rel="noreferrer">1964 article for IEEE</a>, Noyce wrote, &quot;Military and space applications accounted for essentially the entire integrated circuits market last year, and will use over 95 per cent of the integrated circuits produced this year.&quot;</p><p>In 1965, the year that Gordon Moore wrote the <em><a href="https://www.cs.utexas.edu/~fussell/courses/cs352h/papers/moore.pdf" target="_blank" rel="noreferrer">Cramming More Components onto Integrated Circuits</a></em> paper that birthed Moore&#39;s Law, ICs had reached cost parity with discrete components, at around $10, and were beginning to beat them. It was around this time that the Minuteman II program, which now used Texas Instruments ICs, became the technology&#39;s largest buyer. That meant two things - 1) there were multiple large buyers of ICs and 2) there was competition - which combined caused Noyce to cut prices again, down to $2, and again, to $1. The cash coming in from Apollo allowed him to attack the commercial market with lower prices.</p><p>And it worked. By the end of the decade, America beat the Russians to the Moon, and Burroughs released the B2500 computer, the first to use ICs.</p><p>From that point forward, Moore&#39;s Law has largely been driven by demand from the much larger and faster-moving commercial market. But the IC would not have come down the cost curve so quickly - and Moore&#39;s Law, that self-fulfilling prophecy, may never have been coined or executed against - without the early space and military demand. It is to these Buyers of Capabilities that we owe the computer-powered world we inhabit today.</p><p>Something similar might be happening with Data Centers today.</p><h3 id="data-center-demand" tabindex="-1"><strong>Data Center Demand</strong> <a class="header-anchor" href="#data-center-demand" aria-label="Permalink to &quot;**Data Center Demand**&quot;">​</a></h3><p>There is a sentiment floating around that we can&#39;t build hard things in America anymore, but by any measure, modern AI data centers are hard assets to build and operate, and we are building a lot of very big ones. Western hyperscalers, labs, and neoclouds will spend something like$750 billion this year and more than $1 trillion next year building them. <a href="https://www.goldmansachs.com/insights/articles/tracking-trillions-the-assumptions-shaping-scale-of-the-ai-build-out" target="_blank" rel="noreferrer">Goldman estimates</a> that AI CapEx will take $7.6 trillion of capital between 2026 and 2031 across Compute, &quot;Data Centers,&quot; and Power.</p><p><a href="https://substackcdn.com/image/fetch/$s_!QvWm!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F0fd798ff-e3f5-4ef1-865c-87807682fd38_908x416.png" target="_blank" rel="noreferrer"></a><em>Goldman Sachs</em></p><p>This is an enormous amount of CapEx, absolutely, historically, any-way-you-slice-itly. With US GDP around $32 trillion, this year&#39;s spend represents 2.4% of GDP. Assuming GDP grows by an aggressive 3% next year, AI CapEx will account for 3.1% of GDP. For context, the Manhattan Project reached 0.4% of GDP, the late-90s telecom bubble reached 1.2%, and even the Apollo Program only hit 0.4%. To find a more GDP-dominating project, you&#39;d need to look to one of the two World Wars, the New Deal, or the Railroad Boom.</p><p><a href="https://substackcdn.com/image/fetch/$s_!RyQ4!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F3a65a10d-9e2a-4027-b3f2-596f0e75d972_908x469.png" target="_blank" rel="noreferrer"></a><em><a href="https://x.com/Melt_Dem/status/2010794381343850612?s=20" target="_blank" rel="noreferrer">Via Meltem Demirors</a></em></p><p>For a little more context, the $15 billion per year that Anthropic will pay SpaceX for the use of two of its Colossus data centers is roughly 60% of NASA&#39;s entire annual budget.</p><p><a href="https://www.notboring.co/p/thank-god-for-data-centers" target="_blank" rel="noreferrer"> Read more </a></p><hr><h2 id="weekly-dose-of-optimism-194" tabindex="-1"><a href="https://www.notboring.co/p/weekly-dose-of-optimism-194" target="_blank" rel="noreferrer">Weekly Dose of Optimism #194</a> <a class="header-anchor" href="#weekly-dose-of-optimism-194" aria-label="Permalink to &quot;[Weekly Dose of Optimism #194](https://www.notboring.co/p/weekly-dose-of-optimism-194)&quot;">​</a></h2><p><em>🚀 Not Boring | 2026-05-22</em></p><p><a href="https://substackcdn.com/image/fetch/$s_!dnXa!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fb67bd8bd-37fc-420a-bdc8-309e8b3cc10d_1200x600.png" target="_blank" rel="noreferrer"></a></p><p>Hi friends 👋,</p><p>Happy Friday and welcome to our 194th Weekly Dose of Optimism. I&#39;m emailing you from beautiful Utah, where I attended the Abundance Institute Gala last night and got to talk nuclear with Oklo&#39;s Jake DeWitte and General Matter&#39;s Scott Nolan, and where I&#39;ll be spending today at the state&#39;s Operation Gigawatt Conference.</p><p>It&#39;s hard not to feel the optimism in the mountain air. When we started writing the Dose a few years back, nuclear was a controversial dream. Today, we&#39;re heading into the Memorial Day Weekend that kicks off the summer during which multiple new reactors will go critical for the first time.</p><p>Plus, you&#39;re about to read one of the most action-packed Doses in Dose history.</p><p>Things are moving fast, and mostly for the better. Happy Memorial Day Weekend, y&#39;all.</p><hr><h4 id="today-s-weekly-dose-if-brought-to-you-by-lightwork" tabindex="-1">Today&#39;s Weekly Dose if brought to you by… <a href="http://lightworkhome.com/notboring" target="_blank" rel="noreferrer">Lightwork</a> <a class="header-anchor" href="#today-s-weekly-dose-if-brought-to-you-by-lightwork" aria-label="Permalink to &quot;Today&#39;s Weekly Dose if brought to you by… [Lightwork](http://lightworkhome.com/notboring)&quot;">​</a></h4><p><a href="http://lightworkhome.com/notboring" target="_blank" rel="noreferrer"></a></p><p><em>It turns out, my house has been making me worse at writing. Sorry about that. I have it under control now.</em></p><p><em><a href="http://lightworkhome.com/notboring" target="_blank" rel="noreferrer">Lightwork</a> came by my place recently and tested our air and water quality, light sources, likelihood of mold, electromagnetic exposure (turns out <a href="https://www.notboring.co/p/electromagnetism-secretly-runs-the" target="_blank" rel="noreferrer">electromagnetism does run the world</a>), and household products. It was an awesome experience. I learned a lot, including that my home&#39;s air quality and lighting were undermining my energy levels, our shower water was full of VOCs whose vapor I was inhaling, and a whole lot more.</em></p><p><em>Lightwork &#39;s assessments are concierge evaluations where they test every aspect of your home that could be impacting your health, produce a science-backed, in-depth report on all their findings, and then help you fix all the issues they uncover. I recommend them. Check them out!</em></p><p><a href="http://lightworkhome.com/notboring" target="_blank" rel="noreferrer">Book a Free Consultation Today</a></p><hr><h4 id="_1-retatrutide-stuns-in-phase-3-obesity-trial" tabindex="-1">(1) <a href="https://investor.lilly.com/news-releases/news-release-details/lillys-triple-agonist-retatrutide-delivered-powerful-weight-loss" target="_blank" rel="noreferrer">Retatrutide Stuns In Phase 3 Obesity Trial</a> <a class="header-anchor" href="#_1-retatrutide-stuns-in-phase-3-obesity-trial" aria-label="Permalink to &quot;(1) [Retatrutide Stuns In Phase 3 Obesity Trial](https://investor.lilly.com/news-releases/news-release-details/lillys-triple-agonist-retatrutide-delivered-powerful-weight-loss)&quot;">​</a></h4><p><em>Eli Lily</em></p><p><a href="https://substackcdn.com/image/fetch/$s_!ON-_!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ff5a18d85-0c0b-4433-979e-90d2e7bbd40d_1286x1616.jpeg" target="_blank" rel="noreferrer"></a></p><p>Yesterday morning, Eli Lilly reported topline results from TRIUMPH-1, the Phase 3 trial for retatrutide in adults with obesity and at least one weight-related comorbidity. Here&#39;s a <a href="https://x.com/maxmarchione/status/2057482589305450738?s=20" target="_blank" rel="noreferrer">summary of the results</a> from Superpower founder and peptide enthusiast Max Marchione:</p><ul><li><p>28.3% bodyweight lost on 12mg over 80 weeks</p></li><li><p>70.3 pounds on avg. or 31.9 kg</p></li><li><p>45.3% of patients hit 30%+ weight loss (this is bariatric surgery territory)</p></li><li><p>30.3% weight loss (85 lbs) at 104 weeks in higher-BMI patients</p></li><li><p>65.3% of 12mg patients dropped below the obesity BMI threshold</p></li><li><p>19% loss on 4mg over 80 weeks (47.2 lbs) with fewer dropouts than placebo (4.1% vs 4.9%)</p></li><li><p>significant drops in blood pressure, triglycerides, non-HDL cholesterol, waist circumference, and hsCRP</p></li><li><p>no cardiac or liver signals</p></li></ul><p>These are bariatric surgery results in a shot, with a bunch of freebies thrown in.</p><p>People have been excited about reta on social media for a while, but it&#39;s still gray market, so this is a key step towards getting it to the general public, and just an astonishing set of results. People are losing 28.3% of their bodyweight, or 70 pounds, in less than two years!</p><p>For context, Zepbound (tirzepatide) tops out around 20-22% weight loss in its big trials, and the previous-generation Wegovy (semaglutide) at around 15%.</p><p>Retatrutide is the first triple hormone receptor agonist (GIP + GLP-1 + glucagon). We previewed this back in <a href="https://www.notboring.co/p/weekly-dose-of-optimism-175" target="_blank" rel="noreferrer">Dose #175</a>, in our piece on grey-market peptides and Gen3 GLP-1/GIP/glucagon agonists. The author of the essay we covered, <em><a href="https://vectorculture.substack.com/p/not-for-human-consumption" target="_blank" rel="noreferrer">Not for Human Consumption</a>,</em> called these drugs &quot;the holy grail of weight loss medications&quot; before any of them had a Phase 3 readout. Now one of them does.</p><p>This is Lebron-level. Unbelievably hyped out of the gate, and then exceeds the hype.</p><p>As with all of these miracle drugs, there are positive side effects beyond weight loss. Retatrutide reduced osteoarthritis knee pain by an average of 75.8%, with more than 1 in 8 patients reporting they were completely free of knee pain at the end of the trial. LDL cholesterol dropped 20%. 72% of prediabetic participants returned to normal blood sugar levels. Seven more Phase 3 readouts are expected this year, including diabetes, sleep apnea, chronic back pain, and cardiorenal outcomes.</p><p>Get ready to get hot and healthy. It&#39;s Reta Summer (in 2027).</p><h4 id="_2-colossal-biosciences-hatches-chick-from-artificial-eggs" tabindex="-1"><strong>(2)<a href="https://x.com/colossal/status/2056708864096018584?s=20" target="_blank" rel="noreferrer">Colossal Biosciences Hatches Chick From Artificial Eggs</a></strong> <a class="header-anchor" href="#_2-colossal-biosciences-hatches-chick-from-artificial-eggs" aria-label="Permalink to &quot;**(2)[Colossal Biosciences Hatches Chick From Artificial Eggs](https://x.com/colossal/status/2056708864096018584?s=20)**&quot;">​</a></h4><p>&quot;Before we named the stars, before we mapped the atom, we asked ourselves an impossible question: which came first, the chicken or the egg?&quot;</p><p>On Monday, Ben Lamm&#39;s Colossal Biosciences announced that it has hatched 26 healthy chicks from a fully artificial egg, an oval printed shell coated in an oxygen-permeable membrane that lets an embryo develop from poured-in yolk to pipping bird, without a biological eggshell. Researchers crack a freshly laid fertilized egg, pour the contents into the artificial shell (Colossal adds ground-up calcium back in, because the embryo eats the shell as it grows), and watch through the top window as eyes form, vasculature spreads, and, 18 days later, a chick taps its way out.</p><p>Real scientists will tell you (and MIT Tech Review&#39;s Antonio Regalado dutifully <a href="https://www.technologyreview.com/2026/05/19/1137471/colossal-biosciences-is-growing-chickens-in-a-3d-printed-container/" target="_blank" rel="noreferrer">did</a>) that growing birds outside the shell isn&#39;t new. A Japanese group hatched quail in 1998. Katsuya Obara hatched chickens under transparent plastic film in 2024. Colossal&#39;s marketing is, per Regalado, &quot;pure Hollywood.&quot; Which is kind of fair but too clucking cynical.</p><p>Colossal&#39;s real engineering advance is the membrane, which lets the embryo pull enough oxygen from ambient air that the system doesn&#39;t need supplemental gas. Previous shell-less methods did, and chicks tended to die. I like the version in which the chicks live, Regalado.</p><p>While this experiment was on a chicken, we have plenty of those. Colossal likes to de-extinct. Its stated goal is the 12-foot, 500-pound South Island giant moa, which laid four-liter eggs no living bird is large enough to surrogate. Colossal staff are reportedly already calling the prototype scaled-up version the &quot;salad spinner.&quot; More immediately, the artificial egg is a tool for genetic rescue of endangered birds and, as per our discussion in <a href="https://www.notboring.co/p/weekly-dose-of-optimism-186" target="_blank" rel="noreferrer">Dose #186</a> with not boring capital portfolio company <a href="https://neion.bio/" target="_blank" rel="noreferrer">Neion Bio</a>, a substrate for transgenic chickens producing therapeutic proteins in egg whites at a fraction of mammalian cell culture costs.</p><p>This is the first member of what Colossal calls its &quot;exogenous development&quot; family. Up next: artificial wombs for marsupials.</p><p>With this chicken breakthrough, it feels like humans have crossed a road.</p><h4 id="_3-spacex-launches-s-1" tabindex="-1">(3) <a href="https://www.sec.gov/Archives/edgar/data/1181412/000162828026036936/spaceexplorationtechnologi.htm" target="_blank" rel="noreferrer">SpaceX Launches S-1</a> <a class="header-anchor" href="#_3-spacex-launches-s-1" aria-label="Permalink to &quot;(3) [SpaceX Launches S-1](https://www.sec.gov/Archives/edgar/data/1181412/000162828026036936/spaceexplorationtechnologi.htm)&quot;">​</a></h4><blockquote><p><em>For the entirety of its existence, human civilization has lived on a single celestial body: Earth. The current paradigm, in which human civilization is confined to one planet, exposes humanity to existential threats that are unpredictable and uncontrollable on a planetary scale. By moving beyond the only home we have ever known, we ensure species-level redundancy and that the light of consciousness will not be tied to a single planet subject to the inevitable hazards of a harsh and vast universe. We do not want humans to have the same fate as dinosaurs.</em></p></blockquote><p><a href="https://substackcdn.com/image/fetch/$s_!NVG3!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F1793b624-cf49-40fe-b276-ad4daa692c2c_1586x826.png" target="_blank" rel="noreferrer"></a></p><p>On Wednesday, SpaeX dropped what may have been the most highly-anticipated S-1 in the history of the planet (until Anthropic files later this year). You can read it <a href="https://www.sec.gov/Archives/edgar/data/1181412/000162828026036936/spaceexplorationtechnologi.htm" target="_blank" rel="noreferrer">here</a>.</p><p>Financial highlights include:</p><ul><li><p><strong>Revenue:</strong> $4.69B (run-rate ~$19B)</p></li><li><p><strong>Operating loss:</strong> $(1.94B), but Adjusted EBITDA of +$1.13B</p></li><li><p><strong>Connectivity (Starlink) prints cash:</strong> $3.26B revenue, $1.19B operating income in just the first quarter. Its revenue is growing ~50% per year, and profitability is growing faster.</p></li><li><p><strong>AI is losing money for now …:</strong> $818M revenue, $(2.47B) operating loss in Q1. Capex on AI alone was $7.7B in Q1, more than Space ($1.05B) and Connectivity ($1.33B) combined, by far.</p></li><li><p><strong>But has the monster TAM</strong> : AI infra, consumer subscriptions, digital advertising, and enterprise applications - the AI segment - has a company-estimated TAM of $26.5 trillion, which seems small when you consider the size of the universe and the potential to spread Enterprise Applications throughout it.</p></li></ul><p><a href="https://substackcdn.com/image/fetch/$s_!P8z4!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Ff1d17734-2cbc-4938-96be-19e0ac4ebbb6_1262x802.png" target="_blank" rel="noreferrer"></a></p><p>SpaceX also disclosed that it&#39;s doing a <em>second</em> compute deal with Anthropic, in which Dario &amp; Co. will pay SpaceX $1.25 billion <em>per month</em> for Colossus 2, which is nearly as much as entire SpaceX makes now. For now, it&#39;s selling compute on earth, but per the S-1, it plans to begin deploying orbital compute in 2028 and scale it to 100 GW of compute launched annually, which would make Colossus seem like a pale blue dot.</p><p>Starlink, which had been the bull case until AI, is at 9,600 satellites, 10.3 million subscribers across 164 countries, and now accounts for ~75% of all active maneuverable satellites in orbit.</p><p>There is no one operating at a higher level than Elon and the SpaceX team, across everything from terrestrial data centers to rockets to satellites to, soon, Terafab. After more than 20 years, it&#39;s awesome to see the company go public (and generate some much-needed DPI for the venture and seven-layer-SPV ecosystems). Is the price a little high? Maybe, yeah, sure. But what would you pay to own a <em><a href="https://www.notboring.co/p/scarce-assets" target="_blank" rel="noreferrer">Scarce Asset</a></em> that catches Statue of Liberty-sized rockets with chopsticks…</p><p>We&#39;ll find out in June.</p><p>In the meanting, after scrapping the launch of Starship v3 last night, SpaceX is giving it another go today. What a way to launch summer.</p><h4 id="_4-gpt-5-5-pro-makes-breakthrough-on-erdos-planar-distance-problem" tabindex="-1">(4) <a href="https://x.com/OpenAI/status/2057176201782075690?s=20" target="_blank" rel="noreferrer">GPT 5.5 Pro Makes Breakthrough on Erdős Planar Distance Problem</a> <a class="header-anchor" href="#_4-gpt-5-5-pro-makes-breakthrough-on-erdos-planar-distance-problem" aria-label="Permalink to &quot;(4) [GPT 5.5 Pro Makes Breakthrough on Erdős Planar Distance Problem](https://x.com/OpenAI/status/2057176201782075690?s=20)&quot;">​</a></h4><p>Take <em>n</em> dots on a piece of paper. How many pairs of dots can sit exactly one unit apart from each other?</p><p>Paul Erdős posed this in 1946, conjectured the answer grows just barely faster than <em>n</em> , and offered cash for a resolution. For 80 years, the best constructions anyone could find were boring square grids, and most of combinatorial geometry treated Erdős&#39;s upper bound as essentially right.</p><p>This week, an internal general-purpose OpenAI reasoning model produced a proof that disproves it. The model isn&#39;t math-specific, it just thought for a long time and burned an <a href="https://x.com/willdepue/status/2057213893857165701?s=20" target="_blank" rel="noreferrer">estimated</a> ~$1,000 max worth of tokens, which is pretty affordable for an 80 year old unsolved problem! It found that there&#39;s an infinite family of point arrangements that beat the grid, polynomially. Erdős was wrong, and his &quot;favorite problem&quot; is settled.</p><p>How&#39;d it pull it off? Instead of more clever geometry, it pulled in algebraic number theory (specifically, <em>infinite class field towers</em> and Golod-Shafarevich theory, of course, why didn&#39;t I think of that) to construct number systems with the right symmetries, then read the geometric configurations off of those. No human had tried this connection. Thomas Bloom thinks it will unlock other long-stuck problems in discrete geometry.</p><p>And, importantly, it&#39;s verified. Last October, OpenAI <a href="https://x.com/kevinweil/status/1843..." target="_blank" rel="noreferrer">claimed</a> GPT-5 had solved ten Erdős problems; on inspection, it had just surfaced answers from the literature. This time, it got external review by Fields Medalist Tim Gowers and Will Sawin at Princeton, with a companion paper. Gowers&#39;s verdict: &quot;if a human had written the paper and submitted it to the <em>Annals of Mathematics</em> , I would have recommended acceptance without any hesitation.&quot; It also got endorsements from Noga Alon, Melanie Wood, Arul Shankar. Shankar said the models &quot;are capable of having original ingenious ideas, and then carrying them out to fruition.&quot; The full proof is available as a public PDF.</p><p>Ten months ago, frontier models were at IMO-gold level. Really smart high schoolers, basically. Now, they&#39;re doing <em>Annals</em> -worthy novel work.</p><p>I&#39;ve been more skeptical about AI than I normally am about new technologies, and less excited than the average person in tech. Per the evidence that keeps coming out, I&#39;ve been wrong. On the business side and the capabilities side, the pace has been truly remarkable, and I can&#39;t wait to see what problems they&#39;ll solve for us in the years ahead.</p><h4 id="_5-sendcutsend-raises-110m-at-1b-valuation" tabindex="-1">(5) <a href="https://x.com/jimbelosic/status/2056757837951574355?s=20" target="_blank" rel="noreferrer">SendCutSend Raises $110M at $1B Valuation</a> <a class="header-anchor" href="#_5-sendcutsend-raises-110m-at-1b-valuation" aria-label="Permalink to &quot;(5) [SendCutSend Raises $110M at $1B Valuation](https://x.com/jimbelosic/status/2056757837951574355?s=20)&quot;">​</a></h4><p><em>Jim Belosic (SendCutSend)</em></p><p><a href="https://substackcdn.com/image/fetch/$s_!VYfO!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F61e3f89b-e4f6-4076-939a-0b818a392a68_1200x480.jpeg" target="_blank" rel="noreferrer"></a></p><p>Jim Belosic started SendCutSend in 2018 because he couldn&#39;t get custom metal parts fast enough for the cars and motorcycles he was restoring. Eight years later, bootstrapped to this point on credit cards, savings, a PayPal loan, and bank-financed machines, the Reno laser-cutting and bending shop is doing roughly $200 million in revenue, growing 100% year over year, and turning into one of the most important on-demand manufacturers in America.</p><p>Austin Vernon&#39;s February essay <em><a href="https://www.austinvernon.site/blog/manufacturing.html" target="_blank" rel="noreferrer">Speed Can Reindustrialize America</a></em> is the best piece on why the company is so impressive and potentially important. Vernon&#39;s argument is that the US is great at high-volume manufacturing and terrible at low-volume, short-lead-time custom work because soft costs (quoting, programming, billing, all the white-collar overhead) swamp the actual fabrication cost on small orders. SendCutSend&#39;s whole company is an attack on soft costs: instant quotes, one-click buying, software-routed production. It&#39;s generating ~$275K revenue per employee, and the market would support a hell of a lot of employees.</p><p>Interestingly, Patrick Collison was the one person Vernon thanked for feedback, right above the &quot;Funding Opportunities Apendix.&quot;</p><p><a href="https://substackcdn.com/image/fetch/$s_!_kor!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F5202ecfd-5db0-4e94-9c9c-f41ebbe8273b_1076x286.png" target="_blank" rel="noreferrer"></a></p><p>And I guess Collison took it literally, because he reached out to Belosic about investing, and although SCS had never taken outside capital, he decided to take money from the Collisons, Sequoia (Andrew Reed), and Paradigm (Matt Huang) to go bigger, faster.</p><p>Jim and SCS are easy to root for and have become a cult classic over the past few years. Now, the cat&#39;s out of the bag, the money is in the bank, and IT&#39;S TIME TO BUILD.</p><p>In other great news for building stuff here, Amca raised $300M at $1B+ from Caffeinated and crew. Amca builds and modernize factories to design and produce critical aerospace and defense components that are supply-constrained and often sole-sourced.</p><p>Jai Malik&#39;s eighteen-month-old El Segundo startup already runs factories in California, Iowa, and New York, supplies components for the F-35, and uses its RAPID software platform to deliver parts to BAE, Airbus, Textron, Honeywell, and GE Aerospace 67% faster than the legacy defense supply chain. Now, it can make more of the critical components on which the country runs.</p><h4 id="extra-doses-science-breakthroughs-anthropic-valar-atomics-quantum-investment-grindslop" tabindex="-1">Extra Doses: Science Breakthroughs, Anthropic, Valar Atomics, Quantum Investment, Grindslop <a class="header-anchor" href="#extra-doses-science-breakthroughs-anthropic-valar-atomics-quantum-investment-grindslop" aria-label="Permalink to &quot;Extra Doses: Science Breakthroughs, Anthropic, Valar Atomics, Quantum Investment, Grindslop&quot;">​</a></h4><p><a href="https://www.notboring.co/p/weekly-dose-of-optimism-194" target="_blank" rel="noreferrer"> Read more </a></p><hr>',154)])])}const m=t(n,[["render",s]]);export{u as __pageData,m as default};
